from typing import Set, Optional, Dict, Any

class InventoryManager:
    def __init__(self):
        self.inventory: Dict[str, Dict[str, Any]] = {}
        self.skus: Set[str] = set()

    def add_product(self, sku: str, product: Dict[str, Any]) -> None:
        if self._is_valid_sku(sku):
            if sku in self.skus:
                raise ValueError(f"SKU '{sku}' already exists in inventory.")
            self.skus.add(sku)
            self.inventory[sku] = product
        else:
            raise ValueError(f"Invalid SKU format: {sku}")

    def update_product(self, sku: str, product: Dict[str, Any]) -> None:
        if not self._is_valid_sku(sku):
            raise ValueError(f"Invalid SKU format: {sku}")
        if sku not in self.skus:
            raise ValueError(f"SKU '{sku}' not found in inventory.")
        self.inventory[sku] = product

    def delete_product(self, sku: str) -> None:
        if not self._is_valid_sku(sku):
            raise ValueError(f"Invalid SKU format: {sku}")
        if sku not in self.skus:
            raise ValueError(f"SKU '{sku}' not found in inventory.")
        self.skus.remove(sku)
        del self.inventory[sku]

    def search_product(self, sku: str) -> Optional[Dict[str, Any]]:
        if not self._is_valid_sku(sku):
            return None
        return self.inventory.get(sku, None)

    def _is_valid_sku(self, sku: str) -> bool:
        # Simple validation: check if SKU is alphanumeric and has length >= 3
        if not sku or not sku.isalnum() or len(sku) < 3:
            return False
        return True
