#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SEATS 10

// Structure to represent a seat
typedef struct {
    int seatNumber;
    int isOccupied;
} Seat;

// Structure to represent a queue
typedef struct {
    Seat *elements;
    int front;
    int rear;
    int size;
} Queue;

// Initialize the queue
Queue *createQueue() {
    Queue *q = (Queue *)malloc(sizeof(Queue));
    if (q == NULL) return NULL;
    q->elements = (Seat *)malloc(MAX_SEATS * sizeof(Seat));
    if (q->elements == NULL) return NULL;
    q->front = 0;
    q->rear = 0;
    q->size = 0;
    return q;
}

// Enqueue a seat
void enqueue(Queue *q, int seatNumber) {
    if (q->size == MAX_SEATS) {
        printf("Queue is full. Cannot enqueue.\n");
        return;
    }
    q->elements[q->rear++] = (Seat) { seatNumber, 0 };
    q->size++;
}

// Dequeue a seat
Seat dequeue(Queue *q) {
    if (q->size == 0) {
        printf("Queue is empty. Cannot dequeue.\n");
        return (Seat) { -1, 1 };
    }
    Seat seat = q->elements[q->front++];
    q->size--;
    return seat;
}

// Book a seat
Seat bookSeat(Queue *q, int seatNumber) {
    if (seatNumber < 1 || seatNumber > MAX_SEATS) {
        printf("Invalid seat number.\n");
        return (Seat) { -1, 1 };
    }
    Seat seat = dequeue(q);
    if (seat.seatNumber == seatNumber) {
        seat.isOccupied = 1;
        enqueue(q, seatNumber);
        return seat;
    }
    return (Seat) { -1, 1 };
}

// Check if seat is available
int isAvailable(Queue *q, int seatNumber) {
    Seat seat = dequeue(q);
    if (seat.seatNumber == seatNumber) {
        enqueue(q, seatNumber);
        return 1;
    }
    return 0;
}

// Handle overbooking
void handleOverbooking(Queue *q) {
    int overbooked = 0;
    for (int i = 1; i <= MAX_SEATS; i++) {
        if (isAvailable(q, i)) {
            overbooked++;
        }
    }
    if (overbooked > 0) {
        printf("Overbooking detected. Cannot allocate more seats.\n");
    }
}

// Main function
int main() {
    Queue *q = createQueue();
    if (q == NULL) {
        printf("Failed to create queue.\n");
        return 1;
    }

    // Book seats
    for (int i = 1; i <= 10; i++) {
        Seat seat = bookSeat(q, i);
        if (seat.seatNumber != -1) {
            printf("Seat %d booked.\n", seat.seatNumber);
        } else {
            printf("Failed to book seat %d.\n", i);
        }
    }

    // Handle overbooking
    handleOverbooking(q);

    // Free resources
    free(q->elements);
    free(q);
    return 0;
}

