fn shuffle_array<T: PartialEq + Clone>(arr: &[T]) -> Result<Vec<T>, String> {
    if arr.is_empty() {
        return Err("Empty array".to_string());
    }

    let mut shuffled = arr.to_vec();
    let mut rng = rand::thread_rng();

    for i in 0..shuffled.len() {
        let j = rng.gen_range(0..shuffled.len());
        std::mem::swap(&mut shuffled[i], &mut shuffled[j]);
    }

    Ok(shuffled)
}

fn main() {
    // Example usage
    let arr = vec![1, 2, 3, 4, 5];
    match shuffle_array(&arr) {
        Ok(shuffled) => println!("Shuffled array: {:?}", shuffled),
        Err(e) => eprintln!("Error: {}", e),
    }
