using namespace std;

class LogEntry {
public:
    int id;
    time_t timestamp;
    string event;

    LogEntry(int id, time_t timestamp, string event) : id(id), timestamp(timestamp), event(event) {}
};

class LogDatabase {
public:
    vector<LogEntry> logs;
    map<time_t, vector<int>> timestampToEntries;

    void addLogEntry(int id, time_t timestamp, string event) {
        logs.push_back(LogEntry(id, timestamp, event));
        timestampToEntries[timestamp].push_back(id);
    }

    void updateLogEntry(int id, time_t timestamp, string event) {
        auto it = find_if(logs.begin(), logs.end(), [id](const LogEntry& entry) {
            return entry.id == id;
        });
        if (it != logs.end()) {
            it->event = event;
        }
    }

    vector<LogEntry> getLogsWithinRange(time_t start, time_t end) {
        vector<LogEntry> result;
        for (const auto& entry : logs) {
            if (entry.timestamp >= start && entry.timestamp <= end) {
                result.push_back(entry);
            }
        }
        return result;
    }

    void printLogs() {
        for (const auto& entry : logs) {
            cout << "ID: " << entry.id << ", Timestamp: " <<ctime(&entry.timestamp) << ", Event: " << entry.event << endl;
        }
    }
};

int main() {
    LogDatabase db;
    int id = 1;
    time_t timestamp = time(0);
    string event = "Login";

    // Add some log entries
    for (int i = 0; i < 100000; ++i) {
        db.addLogEntry(id++, timestamp++, event);
    }

    // Print all logs
    db.printLogs();

    // Query logs within a specific range
    time_t start = time(0) - 60 * 60; // 1 hour ago
    time_t end = time(0); // Current time

    vector<LogEntry> logsInRange = db.getLogsWithinRange(start, end);
    cout << "Logs within range [" << ctime(&start) << " to " << ctime(&end) << "]:" << endl;
    for (const auto& log : logsInRange) {
        cout << "ID: " << log.id << ", Timestamp: " <<ctime(&log.timestamp) << ", Event: " << log.event << endl;
    }

    // Update a log entry
    db.updateLogEntry(1, timestamp, "Logout");
    cout << "Updated log entry with ID 1." << endl;

    return 0;
}

