    }

    private static Node findLCA(Node root, Node a, Node b) {
        if (a == null || b == null) return null;
        if (a == b) return a;

        // Binary lifting to find LCA
        int logN = LOG;
        int[] up = new int[logN + 1];
        int[] depth = new int[logN + 1];

        // Preprocess for binary lifting
        Node curr = root;
        for (int i = logN; i >= 0; i--) {
            if (curr != null) {
                up[i] = curr;
                curr = curr.left != null ? curr.left : curr.right;
            } else {
                up[i] = null;
            }
        }

        int depthA = 0;
        Node tempA = a;
        while (tempA != null) {
            depthA++;
            tempA = tempA.left != null ? tempA.left : tempA.right;
        }

        int depthB = 0;
        Node tempB = b;
        while (tempB != null) {
            depthB++;
            tempB = tempB.left != null ? tempB.left : tempB.right;
        }

        // Bring deeper node to the same depth
        while (depthA > depthB) {
            a = up[1];
            depthA--;
        }
        while (depthB > depthA) {
            b = up[1];
            depthB--;
        }

        // If nodes are same, return
        if (a == b) return a;

        // Move both up until they meet
        for (int i = logN; i >= 0; i--) {
            if (up[i] != null && a != b) {
                a = up[i];
                b = up[i];
            }
        }

        return a;
    }
}

