import java.io.*;
import java.util.*;

public class InventorySystem {
    private HashMap<String, Item> inventory = new HashMap<>();
    private String filename = "inventory.dat";

    public void addItem(String id, String name, int quantity) {
        if (inventory.containsKey(id)) {
            inventory.get(id).addQuantity(quantity);
        } else {
            inventory.put(id, new Item(name, quantity));
        }
    }

    public void removeItem(String id, int quantity) {
        Item item = inventory.get(id);
        if (item != null) {
            item.reduceQuantity(quantity);
            if (item.getQuantity() == 0) {
                inventory.remove(id);
            }
        }
    }

    public Item findItem(String id) {
        return inventory.get(id);
    }

    public void saveInventory() {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(inventory);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public void loadInventory() {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            inventory = (HashMap<String, Item>) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }

    public static void main(String[] args) {
        InventorySystem inventory = new InventorySystem();
        inventory.addItem("A1", "Apple", 10);
        inventory.addItem("A2", "Banana", 20);
        inventory.addItem("A3", "Cherry", 30);

        System.out.println("Inventory before save: " + inventory.inventory.size());
        inventory.saveInventory();
        System.out.println("Inventory after save: " + inventory.inventory.size());

        inventory.loadInventory();
        System.out.println("Inventory after load: " + inventory.inventory.size());
    }
}

class Item {
    private String name;
    private int quantity;

    public Item(String name, int quantity) {
        this.name = name;
        this.quantity = quantity;
    }

    public void addQuantity(int quantity) {
        this.quantity += quantity;
    }

    public void reduceQuantity(int quantity) {
        this.quantity -= quantity;
    }

    public int getQuantity() {
        return quantity;
    }

    public String getName() {
        return name;
    }
}

