        // Simplified search for demonstration
        vector<int> occurrences;
        for (size_t i = 0; i <= text_.size() - substring.length(); ++i) {
            if (text_.substr(i, substring.length()) == substring) {
                occurrences.push_back(i);
            }
        }
        return occurrences;
    }

private:
    string text_;
    vector<vector<int>> suffix_tree_;
};

int main() {
    try {
        SuffixTree suffixTree("large text document");
        string query = "substring";
        vector<int> occurrences = suffixTree.findOccurrences(query);
        cout << "Occurrences of \"" << query << "\": " << occurrences.size() << " at positions: ";
        for (int pos : occurrences) {
            cout << pos << " ";
        }
        cout << endl;
    } catch (const invalid_argument& e) {
        cout << "Error: " << e.what() << endl;
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <pthread.h>
#include <signal.h>

#define MAX_SENSORS 100
#define MAX_READINGS 1000

typedef struct {
    char name[20];
    int *readings;
    int readings_count;
    pthread_mutex_t mutex;
} Sensor;

typedef struct {
    Sensor *sensors;
    int num_sensors;
    int *all_readings;
    int all_readings_count;
} DataStream;

void *process_sensor(void *arg) {
    Sensor *sensor = arg;
    int i = 0;
    int reading;
    while (1) {
        pthread_mutex_lock(&sensor->mutex);
        reading = sensor->readings[i++];
        if (i >= MAX_READINGS) {
            i = 0;
        }
        pthread_mutex_unlock(&sensor->mutex);
        // Simulate temperature reading
        sleep(1);
        // Add to data stream
        pthread_mutex_lock(&DataStream->mutex);
        DataStream->all_readings[DataStream->all_readings_count++] = reading;
        pthread_mutex_unlock(&DataStream->mutex);
    }
    return NULL;
}

void add_sensor(DataStream *data_stream, const char *name) {
    Sensor *new_sensor = (Sensor *)malloc(sizeof(Sensor));
    strcpy(new_sensor->name, name);
    new_sensor->readings = (int *)malloc(MAX_READINGS * sizeof(int));
    new_sensor->readings_count = 0;
    pthread_mutex_init(&new_sensor->mutex, NULL);
    data_stream->sensors[data_stream->num_sensors++] = new_sensor;
}

void remove_sensor(DataStream *data_stream, int index) {
    if (index >= 0 && index < data_stream->num_sensors) {
        Sensor *sensor = data_stream->sensors[index];
        free(sensor->readings);
        pthread_mutex_destroy(&sensor->mutex);
        free(sensor);
        data_stream->sensors[index] = NULL;
    }
}

void calculate_median(DataStream *data_stream) {
    int n = data_stream->all_readings_count;
    if (n == 0) return;
    // Sort the readings
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (data_stream->all_readings[i] > data_stream->all_readings[j]) {
                int temp = data_stream->all_readings[i];
                data_stream->all_readings[i] = data_stream->all_readings[j];
                data_stream->all_readings[j] = temp;
            }
        }
    }
    int mid = n / 2;
    int median = data_stream->all_readings[mid];
    printf("Median: %d\n", median);
}

void handle_signal(int sig) {
    printf("Signal received: %d\n", sig);
}

int main(int argc, char *argv[]) {
    DataStream data_stream = {0};
    pthread_t *thread_handles = (pthread_t *)malloc(MAX_SENSORS * sizeof(pthread_t));
    int num_threads = 0;

    // Initialize data stream
    data_stream.all_readings = (int *)malloc(MAX_READINGS * sizeof(int));
    data_stream.all_readings_count = 0;

    // Register signal handler
    signal(SIGINT, handle_signal);

    // Add sensors
    add_sensor(&data_stream, "Sensor 1");
    add_sensor(&data_stream, "Sensor 2");
    add_sensor(&data_stream, "Sensor 3");

    // Create threads
    for (int i = 0; i < data_stream.num_sensors; i++) {
        pthread_create(&thread_handles[num_threads], NULL, process_sensor, data_stream.sensors[i]);
        num_threads++;
    }

    // Calculate median in real-time
    while (1) {
        calculate_median(&data_stream);
        sleep(1);
    }

    // Clean up
    for (int i = 0; i < num_threads; i++) {
        pthread_join(thread_handles[i], NULL);
    }
    free(thread_handles);
    free(data_stream.all_readings);
    return 0;
}

