function longestCommonSubsequence(word1, word2) {
    if (!word1 || !word2 || word1.length === 0 || word2.length === 0) {
        throw new Error("Both inputs must be non-empty strings.");
    }

    const m = word1.length;
    const n = word2.length;

    // Create a 2D array for dynamic programming
    const dp = Array.from({ length: m }, () => Array(n).fill(0));

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (word1[i] === word2[j]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
    }

    return dp[m - 1][n - 1];
}

// Example usage
try {
    const result = longestCommonSubsequence("abcdef", "aecdf");
    console.log("Longest Common Subsequence:", result);
} catch (error) {
    console.error("Error:", error.message);
}
