        if (contains(title)) {
            cout << "Error: Book with title " << title << " already exists." << endl;
            return;
        }
        books.push_back(title);
        bookCount++;
    }

    bool contains(const string& title) const {
        return find(books.begin(), books.end(), title) != books.end();
    }

    void removeBook(const string& title) {
        auto it = find(books.begin(), books.end(), title);
        if (it != books.end()) {
            books.erase(it);
            bookCount--;
        } else {
            cout << "Error: Book with title " << title << " not found." << endl;
        }
    }

    void listBooks() const {
        for (const auto& book : books) {
            cout << book << endl;
        }
    }

    bool searchBook(const string& title) const {
        auto it = find(books.begin(), books.end(), title);
        if (it != books.end()) {
            return true;
        }
        return false;
    }

    int getBookCount() const {
        return bookCount;
    }
