from collections import defaultdict

def is_valid_email(email):
    """Check if the email is valid."""
    if not email:
        return False
    if not email.endswith('@'):
        return False
    if not email.split('@')[0]:
        return False
    return True

def load_emails_from_csv(file_path):
    """Load email addresses from a CSV file."""
    emails = []
    if not os.path.exists(file_path):
        print(f"Error: File {file_path} not found.")
        return emails
    try:
        with open(file_path, 'r') as csvfile:
            reader = csv.reader(csvfile)
            for row in reader:
                if row:
                    email = row[0]
                    if is_valid_email(email):
                        emails.append(email)
    except Exception as e:
        print(f"Error loading CSV: {e}")
    return emails

def find_duplicates(emails):
    """Find duplicates in the list of emails."""
    email_counts = defaultdict(int)
    for email in emails:
        email_counts[email] += 1
    duplicates = {email: count for email, count in email_counts.items() if count > 1}
    return duplicates

def flag_duplicates(emails, duplicates):
    """Flag duplicates in the list of emails."""
    flagged_emails = []
    for email in emails:
        if email in duplicates:
            flagged_emails.append(email)
    return flagged_emails

def main():
    if len(sys.argv) < 2:
        print("Usage: python script.py <csv_file>")
        return

    csv_file = sys.argv[1]
    emails = load_emails_from_csv(csv_file)
    if not emails:
        print("No valid emails found.")
        return

    duplicates = find_duplicates(emails)
    flagged = flag_duplicates(emails, duplicates)

    print(f"Found {len(duplicates)} duplicate emails.")
    print(f"Flagged emails: {flagged}")

if __name__ == "__main__":
