// Define a structure for user activity
struct UserActivity {
    int userId;
    int activityCount;
};

// O(n log n) sorting algorithm
void sortUsers(const std::vector<UserActivity>& activities, std::vector<int>& userIds) {
    std::sort(activities.begin(), activities.end(), [](const UserActivity& a, const UserActivity& b) {
        return a.activityCount > b.activityCount;
    });
    // Extract userIds in descending order of activity count
    for (int i = 0; i < activities.size(); ++i) {
        userIds.push_back(activities[i].userId);
    }
}

// Efficient memory management using smart pointers
std::unique_ptr<std::vector<UserActivity>> loadActivities(const std::string& filePath) {
    std::unique_ptr<std::vector<UserActivity>> activities(new std::vector<UserActivity>());
    std::ifstream file(filePath, std::ios::binary);
    if (file.is_open()) {
        size_t fileSize = file.tellg();
        file.seekg(0, std::ios::end);
        size_t fileSize = file.tellg();
        file.seekg(0, std::ios::beg);
        std::vector<UserActivity> temp;
        size_t count = 0;
        while (count < fileSize) {
            UserActivity activity;
            file.read(reinterpret_cast<char*>(&activity.userId), sizeof(int));
            file.read(reinterpret_cast<char*>(&activity.activityCount), sizeof(int));
            temp.push_back(activity);
            count += sizeof(UserActivity);
        }
        *activities = temp;
        file.close();
    }
    return activities;
}

// Real-time data update support
void updateActivities(std::unique_ptr<std::vector<UserActivity>>& activities, int userId, int activityCount) {
    std::lock_guard<std::mutex> lock(activities->mutex);
    for (auto& activity : *activities) {
        if (activity.userId == userId) {
            activity.activityCount += activityCount;
            break;
        }
    }
}

// Graceful handling of data corruption
void handleDataCorruption(std::unique_ptr<std::vector<UserActivity>>& activities) {
    try {
        sortUsers(*activities, std::vector<int>());
    } catch (const std::exception& e) {
        std::cerr << "Data corruption detected: " << e.what() << std::endl;
        // Re-load data and retry
        std::unique_ptr<std::vector<UserActivity>> newActivities = loadActivities("user_activity.log");
        if (newActivities) {
            *activities = std::move(*newActivities);
        }
    }
}

int main() {
    // Simulate real-time data updates
    std::unique_ptr<std::vector<UserActivity>> activities = loadActivities("user_activity.log");
    if (!activities) {
        std::cerr << "Failed to load data." << std::endl;
        return 1;
    }

    // Sort users by activity count
    std::vector<int> userIds;
    sortUsers(*activities, userIds);

    // Display top-k users
    int k = 10;
    std::cout << "Top " << k << " most active users:" << std::endl;
    for (int i = 0; i < std::min(k, userIds.size()); ++i) {
        std::cout << userIds[i] << " (" << userIds[i] << " activities)" << std::endl;
    }

    // Simulate real-time updates
    std::thread updateThread([&activities, &k]() {
        std::this_thread::sleep_for(std::chrono::milliseconds(1000));
        updateActivities(activities, 123, 5);
    });

    // Gracefully handle data corruption
    handleDataCorruption(activities);

    updateThread.join();
    return 0;
}

