fn main() {
    // Input validation for board dimensions
    let mut n = 0;
    loop {
        println!("Enter the number of queens (n):");
        let mut input = String::new();
        io::stdin().read_line(&mut input).expect("Failed to read line");
        let n = input.trim().parse::<usize>().expect("Invalid input");
        if n > 0 {
            break;
        }
        println!("Please enter a positive integer.");
    }

    // Solve 8-Queen Problem using backtracking
    let solution = solve_8_queen(n);

    // Display solution
    if solution.is_some() {
        let solution = solution.unwrap();
        println!("Solution found:");
        for i in 0..n {
            println!("Queen at row {}: column {}", i, solution[i]);
        }
    } else {
        println!("No solution exists for the given board size.");
    }
}

fn solve_8_queen(n: usize) -> Option<Vec<usize>> {
    let mut board = vec![vec![0; n]; n];
    let mut result = Vec::new();

    fn backtrack(row: usize, col: usize, board: &mut Vec<Vec<usize>>, result: &mut Vec<Vec<usize>>) {
        if row == n {
            result.push(board.clone());
            return;
        }

        for col in 0..n {
            if is_safe(board, row, col, n) {
                board[row][col] = 1;
                backtrack(row + 1, col, board, result);
                board[row][col] = 0;
            }
        }
    }

    backtrack(0, 0, &mut board, &mut result);
    result.first().cloned()
}

fn is_safe(board: &Vec<Vec<usize>>, row: usize, col: usize, n: usize) -> bool {
    for i in 0..row {
        if board[i][col] == 1 || 
           board[i][col] == 1 && 
           (i - row).abs() == (i - col).abs() {
            return false;
        }
    }
    true
}
