import sys
import heapq

class City:
    def __init__(self, name, x, y):
        self.name = name
        self.x = x
        self.y = y

class Edge:
    def __init__(self, u, v, distance):
        self.u = u
        self.v = v
        self.distance = distance
        self.u_name = city_list[u].name
        self.v_name = city_list[v].name

def load_cities(file_path):
    cities = []
    with open(file_path, 'r') as f:
        for line in f:
            parts = line.strip().split()
            if len(parts) < 3:
                continue
            name = parts[0]
            x = float(parts[1])
            y = float(parts[2])
            cities.append(City(name, x, y))
    return cities

def load_edges(file_path):
    edges = []
    with open(file_path, 'r') as f:
        for line in f:
            parts = line.strip().split()
            if len(parts) < 3:
                continue
            u = int(parts[0])
            v = int(parts[1])
            distance = float(parts[2])
            edges.append(Edge(u, v, distance))
    return edges

def validate_input(cities, edges):
    if not cities:
        raise ValueError("No cities provided.")
    if not edges:
        raise ValueError("No edges provided.")
    for edge in edges:
        if not (0 <= edge.u < len(cities) and 0 <= edge.v < len(cities)):
            raise ValueError("Invalid city indices.")
    return cities, edges

def kruskal_mst(cities, edges):
    cities = list(cities)
    edges = list(edges)
    # Sort edges by distance
    edges.sort(key=lambda x: x.distance)
    parent = list(range(len(cities)))
    def find(u):
        while parent[u] != u:
            parent[u] = parent[parent[u]]
            u = parent[u]
        return u
    def union(u, v):
        root_u = find(u)
        root_v = find(v)
        if root_u == root_v:
            return False
        parent[root_v] = root_u
        return True
    mst = []
    for edge in edges:
        if union(edge.u, edge.v):
            mst.append(edge)
    return mst

def main():
    if len(sys.argv) != 2:
        print("Usage: python mst.py <input_file>")
        return
    input_file = sys.argv[1]
    try:
        cities = load_cities(input_file)
        edges = load_edges(input_file)
        cities, edges = validate_input(cities, edges)
        mst = kruskal_mst(cities, edges)
        print("Minimum Spanning Tree:")
        for edge in mst:
            print(f"From {edge.u_name} to {edge.v_name} with distance {edge.distance}")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
