use std::collections::HashMap;

struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode {
                children: HashMap::new(),
                is_end_of_word: false,
            },
        }
    }

    fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            if let Some(child) = node.children.get(&c) {
                // If child exists, move to it
                node = child;
            } else {
                // Create new child node
                node.children.insert(c, TrieNode {
                    children: HashMap::new(),
                    is_end_of_word: false,
                });
                node = &node.children[c];
            }
        }
        node.is_end_of_word = true;
    }

    fn autocomplete(&self, prefix: &str) -> Vec<String> {
        let mut result = Vec::new();
        let mut node = &self.root;
        for c in prefix.chars() {
            if let Some(child) = node.children.get(&c) {
                node = child;
            } else {
                break; // No more characters to process
            }
        }
        // Collect all words that end at this node
        let mut words = Vec::new();
        // Traverse from current node to root to collect all words
        let mut current = &self.root;
        while let Some(child) = current.children.get(&c) {
            current = child;
            if current.is_end_of_word {
                words.push(c.to_string());
            }
        }
        // Reverse to get the correct order
        words.reverse();
        words
    }
}

fn main() {
    let mut trie = Trie::new();
    trie.insert("apple");
    trie.insert("app");
    trie.insert("application");
    trie.insert("application");
    trie.insert("app");
    trie.insert("app");

    let prefix = "ap";
    let suggestions = trie.autocomplete(prefix);
    println!("Suggestions for '{}': {:?}", prefix, suggestions);
