// Suffix Tree implementation (simplified for demonstration)
class SuffixTreeNode {
    constructor() {
        this.children = {};
        this.isEndOfWord = false;
    }
}

class SuffixTree {
    constructor(str) {
        this.root = new SuffixTreeNode();
        this.str = str;
        this.build();
    }

    build() {
        for (let i = 0; i < this.str.length; i++) {
            this.insert(this.str[i], i);
        }
    }

    insert(char, index) {
        let node = this.root;
        for (let i = 0; i < this.str.length; i++) {
            let charAt = this.str[i];
            if (charAt === char) {
                if (node.children[char] === undefined) {
                    node.children[char] = new SuffixTreeNode();
                }
                node = node.children[char];
                if (i === index) {
                    node.isEndOfWord = true;
                }
                break;
            } else {
                if (node.children[char] === undefined) {
                    node.children[char] = new SuffixTreeNode();
                }
                node = node.children[char];
            }
        }
    }

    longestRepeatedSubstring() {
        let maxLen = 0;
        let maxSubstr = "";
        let node = this.root;
        for (let i = 0; i < this.str.length; i++) {
            if (node.isEndOfWord) {
                maxLen = Math.max(maxLen, i - this.str.indexOf(this.str[i]));
                maxSubstr = this.str.substring(i - maxLen + 1, i + 1);
            }
            if (node.children[this.str[i]] !== undefined) {
                node = node.children[this.str[i]];
            } else {
                node = this.root;
            }
        }
        return maxSubstr;
