class Playlist {
    private Node head;
    private Node tail;
    private int size;

    private static class Node {
        Song song;
        Node prev;
        Node next;

        public Node(Song song) {
            this.song = song;
        }
    }

    public void addSong(Song song) {
        Node newNode = new Node(song);
        if (head == null) {
            head = newNode;
            tail = newNode;
        } else {
            newNode.prev = tail;
            tail.next = newNode;
            tail = newNode;
        }
        size++;
    }

    public void removeSong(Song song) {
        Node current = head;
        while (current != null && current.song != song) {
            current = current.next;
        }
        if (current == null) {
            System.out.println("Song not found.");
            return;
        }
        if (current == head) {
            head = current.next;
            if (head != null) {
                head.prev = null;
            }
        } else if (current == tail) {
            tail = current.prev;
            if (tail != null) {
                tail.next = null;
            }
        } else {
            current.prev.next = current.next;
            current.next.prev = current.prev;
        }
        size--;
    }

    public void rearrangeSongs(Song song, Node newNode) {
        if (head == null) {
            return;
        }
        Node current = head;
        while (current != null && current.song != song) {
            current = current.next;
        }
        if (current == null) {
            return;
        }
        // Insert new node at the position of the song
        Node temp = current.next;
        current.next = newNode;
        newNode.prev = current;
        newNode.next = temp;
        if (temp != null) {
            temp.prev = newNode;
        }
    }

    public boolean searchSong(String title) {
        Node current = head;
        while (current != null) {
            if (current.song.title.equals(title)) {
                return true;
            }
            current = current.next;
        }
        return false;
    }

    public void displayPlaylist() {
        Node current = head;
        while (current != null) {
            System.out.println(current.song);
            current = current.next;
        }
    }

    public int size() {
        return size;
    }
}

public class PlaylistManager {
    public static void main(String[] args) {
        Playlist playlist = new Playlist();
        Song song1 = new Song("Bohemian Rhapsody", "Queen", "4:31");
        Song song2 = new Song("Imagine", "John Lennon", "3:00");
        Song song3 = new Song("Hey Jude", "The Beatles", "3:01");

