const int MAX = 8;

bool isSafe(int board[MAX][MAX], int row, int col, int queenCount) {
    for (int i = 0; i < row; i++) {
        if (board[i][col] || abs(row - i) == abs(col - board[i][col])) {
            return false;
        }
    }
    return true;
}

bool solve(int board[MAX][MAX], int row, int queenCount) {
    if (row == MAX) {
        return true;
    }

    for (int col = 0; col < MAX; col++) {
        if (isSafe(board, row, col, queenCount)) {
            board[row][col] = queenCount;
            if (solve(board, row + 1, queenCount + 1)) {
                return true;
            }
            board[row][col] = 0;
        }
    }
    return false;
}

int main() {
    int board[MAX][MAX];
    if (solve(board, 0, 0)) {
        for (int i = 0; i < MAX; i++) {
            for (int j = 0; j < MAX; j++) {
                cout << board[i][j] << " ";
            }
            cout << endl;
        }
    } else {
        cout << "No solution found." << endl;
    }
    return 0;
}

