public class ShellSortEmployeeSalaries {
    public static void main(String[] args) {
        try {
            // Read CSV file
            File file = new File("salaries.csv");
            List<Integer> salaries = readSalariesFromFile(file);

            // Validate salaries
            if (salaries.isEmpty() || !salaries.stream().allMatch(s -> s > 0)) {
                System.out.println("Invalid salary data.");
                return;
            }

            // Shell sort
            shellSort(salaries);

            // Print sorted salaries
            System.out.println("Sorted salaries:");
            for (int salary : salaries) {
                System.out.print(salary + " ");
            }
        } catch (IOException e) {
            System.out.println("Error reading CSV file: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("Error: " + e.getMessage());
        }
    }

    // Read salaries from CSV file
    private static List<Integer> readSalariesFromFile(File file) throws IOException {
        List<Integer> salaries = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(file))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] parts = line.split(",");
                for (String part : parts) {
                    try {
                        salaries.add(Integer.parseInt(part));
                    } catch (NumberFormatException e) {
                        System.out.println("Invalid number in CSV file: " + part);
                    }
                }
            }
        }
        return salaries;
    }

    // Shell sort implementation
    private static void shellSort(List<Integer> list) {
        int n = list.size();
        int gap = n / 2;
        while (gap > 0) {
            for (int i = gap; i < n; i++) {
                int temp = list.get(i);
                int j = i;
                while (j >= gap && list.get(j - gap) > temp) {
                    list.set(j, list.get(j - gap));
                    j -= gap;
                }
                list.set(j, temp);
            }
            gap /= 2;
        }
    }
}
