const TabHistory = {
  constructor() {
    this.head = null;
    this.tail = null;
    this.currentTab = null;
  },

  // Add a new tab to the history
  addTab(tab) {
    const newNode = {
      tab,
      prev: null,
      next: null
    };

    if (!this.head) {
      this.head = newNode;
      this.tail = newNode;
      this.currentTab = newNode;
    } else {
      this.tail.next = newNode;
      newNode.prev = this.tail;
      this.tail = newNode;
    }
  },

  // Navigate forward
  forward() {
    if (this.currentTab && this.currentTab.next) {
      this.currentTab = this.currentTab.next;
    } else {
      console.error("Cannot forward. No more tabs to navigate to.");
    }
  },

  // Navigate backward
  backward() {
    if (this.currentTab && this.currentTab.prev) {
      this.currentTab = this.currentTab.prev;
    } else {
      console.error("Cannot go back. No more tabs to navigate to.");
    }
  },

  // Open a new tab (clears forward history)
  openNewTab(tab) {
    const newNode = {
      tab,
      prev: null,
      next: null
    };

    if (!this.head) {
      this.head = newNode;
      this.tail = newNode;
      this.currentTab = newNode;
    } else {
      this.tail.next = newNode;
      newNode.prev = this.tail;
      this.tail = newNode;
    }
    this.currentTab = newNode;
  },

  // Close current tab
  closeTab() {
    if (this.currentTab) {
      if (this.currentTab === this.head) {
        this.head = this.head.next;
        if (this.head) {
          this.head.prev = null;
        }
      } else if (this.currentTab === this.tail) {
        this.tail = this.tail.prev;
        if (this.tail) {
          this.tail.next = null;
        }
      } else {
        const prev = this.currentTab.prev;
        const next = this.currentTab.next;
        prev.next = next;
        next.prev = prev;
      }
      this.currentTab = null;
    } else {
      console.error("No tab to close.");
    }
  },

  // Get current tab
  getCurrentTab() {
    return this.currentTab;
  }
};

