void readStudents(vector<Student>& students, const string& filename) {
    ifstream file(filename);
    if (!file) {
        throw runtime_error("Cannot open file");
    }
    string line;
    while (getline(file, line)) {
        if (line.empty()) continue;
        size_t pos = line.find(',');
        if (pos == string::npos) {
            cerr << "Invalid line: " << line << endl;
            continue;
        }
        string name = line.substr(0, pos);
        string gpaStr = line.substr(pos + 1);
        try {
            double gpa = stod(gpaStr);
            students.push_back({name, gpa});
        } catch (const invalid_argument&) {
            cerr << "Invalid GPA value: " << gpaStr << endl;
        }
    }
}

void selectionSort(vector<Student>& students) {
    for (size_t i = 0; i < students.size() - 1; ++i) {
        size_t maxIndex = i;
        for (size_t j = i + 1; j < students.size(); ++j) {
            if (students[j].gpa > students[maxIndex].gpa) {
                maxIndex = j;
            }
        }
        swap(students[i], students[maxIndex]);
    }
}

void displayStudents(const vector<Student>& students) {
    for (const auto& student : students) {
        cout << student.name << " " << student.gpa << endl;
    }
}

