const Dictionary = (() => {
  const cache = new Map();
  const hashFunction = (word) => {
    // Simple hash function for demonstration
    return word.split('').reduce((acc, char) => acc * 37 + char.charCodeAt(0), 0);
  };

  const addWord = (word, definition) => {
    if (cache.has(word)) {
      console.warn(`Word "${word}" already exists in the dictionary.`);
      return false;
    }
    cache.set(word, definition);
    return true;
  };

  const deleteWord = (word) => {
    if (cache.has(word)) {
      cache.delete(word);
      return true;
    }
    return false;
  };

  const getDefinition = (word) => {
    if (cache.has(word)) {
      return cache.get(word);
    }
    return undefined;
  };

  const getHash = (word) => {
    return hashFunction(word);
  };

  return {
    addWord,
    deleteWord,
    getDefinition,
    getHash,
    // Handle edge cases
    hasWord: (word) => cache.has(word),
    wordExists: (word) => cache.has(word)
  };
})();

