using namespace std;

class Stock {
public:
    string name;
    double price;
    Stock(string name, double price) : name(name), price(price) {}
};

class SkipList {
public:
    SkipList(int maxLevel) : maxLevel(maxLevel) {
        // Initialize skip list with dummy nodes
        for (int i = 0; i < maxLevel; ++i) {
            nodes.push_back(nullptr);
        }
    }

    ~SkipList() {
        // Clean up nodes
        for (auto it = nodes.begin(); it != nodes.end(); ++it) {
            if (*it) {
                delete *it;
                it = nodes.begin();
            }
        }
    }

    void insert(const Stock& stock) {
        int level = maxLevel;
        Node* current = head;
        Node* prev = nullptr;

        while (current && current->value.price < stock.price) {
            prev = current;
            current = current->next[level - 1];
            level--;
        }

        if (!current) {
            // Insert at the bottom
            Node* new_node = new Node(stock);
            new_node->next = nullptr;
            new_node->prev = prev;
            if (prev) {
                prev->next[level] = new_node;
            } else {
                head = new_node;
            }
            nodes[level] = new_node;
            level = maxLevel;
        } else if (current->value.price == stock.price) {
            // Duplicate, skip
            return;
        } else {
            // Insert at the appropriate level
            Node* new_node = new Node(stock);
            new_node->next = current->next[level];
            new_node->prev = current->prev[level];
            current->next[level] = new_node;
            new_node->next[level] = current->next[level];
            current->next[level] = new_node;
            nodes[level] = new_node;
            level = maxLevel;
        }
    }

    void delete(const Stock& stock) {
        Node* current = head;
        Node* prev = nullptr;

        while (current && current->value.price != stock.price) {
            prev = current;
            current = current->next;
        }

        if (current) {
            // Remove from the skip list
            if (prev) {
                prev->next[level] = current->next[level];
            } else {
                head = current->next[level];
            }

            // Remove the node from the skip list
            delete current;
            nodes[level] = nullptr;
        }
    }

    Stock* search(double price) {
        Node* current = head;
        Node* prev = nullptr;

        while (current && current->value.price != price) {
            prev = current;
            current = current->next;
        }

        if (current) {
            return &current->value;
        }
        return nullptr;
    }

    vector<Stock> orderedTraversal() {
        vector<Stock> result;
        Node* current = head;
        while (current) {
            result.push_back(current->value);
            current = current->next;
        }
        return result;
    }

private:
    struct Node {
        Stock value;
        Node* next;
        Node* prev;
        int level;
    };

    vector<Node*> nodes;
    Node* head;
    int maxLevel;
};

int main() {
    SkipList skipList(4);

    // Insert some stocks
    skipList.insert(Stock("AAPL", 150.0));
    skipList.insert(Stock("GOOGL", 250.0));
    skipList.insert(Stock("MSFT", 300.0));
    skipList.insert(Stock("AMZN", 120.0));

    // Search for a stock
    Stock* found = skipList.search(150.0);
    if (found) {
        cout << "Found: " << found->name << " at $" << found->price << endl;
    } else {
        cout << "Not found." << endl;
    }

    // Get ordered list
    vector<Stock> ordered = skipList.orderedTraversal();
    for (const auto& stock : ordered) {
        cout << stock.name << " - $" << stock.price << endl;
    }

    return 0;
}

