use std::collections::BinaryHeap;

struct Task {
    id: usize,
    priority: i32,
    description: String,
    due_time: usize,
}

struct Scheduler {
    tasks: BinaryHeap<Task>,
}

impl Scheduler {
    fn new() -> Self {
        Scheduler {
            tasks: BinaryHeap::new(),
        }
    }

    fn insert_task(&mut self, task: Task) {
        self.tasks.push(task);
    }

    fn update_priority(&mut self, task_id: usize, new_priority: i32) {
        // Find the task with the given ID
        let task = self.tasks.iter().find(|t| t.id == task_id).unwrap();
        task.priority = new_priority;
    }

    fn get_highest_priority_task(&self) -> Option<&Task> {
        self.tasks.peek()
    }
}

fn main() {
    let mut scheduler = Scheduler::new();

    // Example tasks
    let task1 = Task {
        id: 1,
        priority: 5,
        description: "Flight check".to_string(),
        due_time: 1000,
    };

    let task2 = Task {
        id: 2,
        priority: 3,
        description: "Sensor calibration".to_string(),
        due_time: 1500,
    };

    let task3 = Task {
        id: 3,
        priority: 4,
        description: "Drone maintenance".to_string(),
        due_time: 800,
    };

    scheduler.insert_task(task1);
    scheduler.insert_task(task2);
    scheduler.insert_task(task3);

    // Update priority of task 2
    scheduler.update_priority(2, 6);

    // Get highest priority task
    if let Some(task) = scheduler.get_highest_priority_task() {
