class OrderBook {
private:
    struct Order {
        int price;
        int quantity;
        bool is_limit;
        int id;
    };

    map<int, vector<Order>> price_map;
    set<int> unique_prices;

    void validateOrder(int price, int quantity, bool is_limit) {
        if (quantity <= 0) {
            throw invalid_argument("Quantity must be positive");
        }
        if (is_limit && quantity == 0) {
            throw invalid_argument("Quantity must be positive");
        }
        if (price < 0) {
            throw invalid_argument("Price must be non-negative");
        }
        if (is_limit && price < 0) {
            throw invalid_argument("Price must be non-negative");
        }
        if (is_limit && price == 0) {
            throw invalid_argument("Price must be positive");
        }
    }

public:
    void insertOrder(int price, int quantity, bool is_limit) {
        validateOrder(price, quantity, is_limit);
        if (price_map.find(price) == price_map.end()) {
            price_map[price] = vector<Order>();
        }
        auto& orders = price_map[price];
        for (int i = 0; i < orders.size(); ++i) {
            if (orders[i].quantity == quantity) {
                orders[i].quantity += quantity;
                return;
            }
        }
        Order new_order = {price, quantity, is_limit, 0};
        orders.push_back(new_order);
    }

    void removeOrder(int price, int quantity, bool is_limit) {
        if (price_map.find(price) == price_map.end()) {
            throw invalid_argument("Price not found");
        }
        auto& orders = price_map[price];
        for (int i = 0; i < orders.size(); ++i) {
            if (orders[i].quantity == quantity) {
                orders.erase(orders.begin() + i);
                return;
            }
        }
        throw invalid_argument("Order not found");
    }

    int queryPriceLevel(int price) {
        if (price_map.find(price) == price_map.end()) {
            throw invalid_argument("Price not found");
        }
        return price_map[price].size();
    }

    int queryTotalQuantity(int price) {
        if (price_map.find(price) == price_map.end()) {
            throw invalid_argument("Price not found");
        }
        int total = 0;
        for (auto& order : price_map[price]) {
            total += order.quantity;
        }
        return total;
    }

    void printBook() {
        for (const auto& price : unique_prices) {
            cout << "Price: " << price << " - Quantity: " << queryTotalQuantity(price) << endl;
        }
    }
};

int main() {
    OrderBook book;
    book.insertOrder(100, 50, true);
    book.insertOrder(100, 30, true);
    book.insertOrder(150, 20, true);
    book.insertOrder(200, 10, true);
    book.insertOrder(200, 5, true);

    cout << "Order Book:" << endl;
    book.printBook();

    try {
        book.removeOrder(100, 20, true);
        book.removeOrder(150, 20, true);
    } catch (const invalid_argument& e) {
        cout << "Error: " << e.what() << endl;
    }

    try {
        cout << "Total quantity at 100: " << book.queryTotalQuantity(100) << endl;
    } catch (const invalid_argument& e) {
        cout << "Error: " << e.what() << endl;
    }

    return 0;
