            root: TrieNode {
                children: HashMap::new(),
                is_end_of_word: false,
            },
        }
    }

    fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            if let Some(child) = node.children.get(&c) {
                // If child exists, move to it
                node = child;
            } else {
                // Create new node if not exists
                node.children.insert(c, TrieNode {
                    children: HashMap::new(),
                    is_end_of_word: false,
                });
                node = &node.children[c];
            }
        }
        node.is_end_of_word = true;
    }

    fn prefix_search(&self, prefix: &str) -> Vec<&str> {
        let mut result: Vec<&str> = Vec::new();
        let mut node = &self.root;
        for c in prefix.chars() {
            if let Some(child) = node.children.get(&c) {
                node = child;
            } else {
                break; // Prefix not found
            }
        }
        // Collect all words ending with the prefix
        let mut words = vec![];
        // Traverse from root to find all words with the prefix
        self._traverse_prefix(&mut node, prefix, &mut words);
        result.extend(words);
        result
    }

    fn _traverse_prefix(&self, node: &TrieNode, prefix: &str, words: &mut Vec<&str>) {
        if node.is_end_of_word {
            words.push(prefix);
        }
        for (c, child) in &node.children {
            self._traverse_prefix(child, prefix + &c, words);
        }
    }

    fn load_words_from_file(&mut self, file_path: &str) {
        let file = File::open(file_path).expect("File not found");
        let reader = BufReader::new(file);
        for line in reader.lines() {
            let line = line.expect("Failed to read line");
            if !line.is_empty() {
                self.insert(&line);
            }
        }
    }
}

fn main() {
    let trie = Trie::new();
    let file_path = "words.txt";
    trie.load_words_from_file(file_path);

    let prefix = "pr";
    let words = trie.prefix_search(prefix);
    println!("Words with prefix '{}': {:?}", prefix, words);
}
