use std::collections::HashMap;
use std::sync::{Mutex, MutexGuard};
use std::thread;
use std::time::Duration;

struct Task {
    id: usize,
    priority: u8,
    content: String,
    next: Option<Box<Task>>,
    prev: Option<Box<Task>>,
}

struct TaskList {
    head: Option<Box<Task>>,
    tail: Option<Box<Task>>,
    tasks: Mutex<HashMap<usize, Task>>,
}

impl TaskList {
    fn new() -> Self {
        TaskList {
            head: None,
            tail: None,
            tasks: Mutex::new(HashMap::new()),
        }
    }

    fn insert(&mut self, task: Task) {
        let mut tasks = self.tasks.lock().unwrap();
        let new_task = Box::new(task);
        let mut current = self.head.as_mut().unwrap();
        while current != Some(&new_task) {
            current = current.as_ref().unwrap().next.as_mut().unwrap();
        }
        current.next = Some(new_task);
        new_task.prev = Some(current);
        tasks.insert(task.id, task);
    }

    fn remove(&mut self, id: usize) {
        let mut tasks = self.tasks.lock().unwrap();
        let task = tasks.remove(&id);
        if task.prev.is_some() {
            let prev = task.prev.as_mut().unwrap();
            prev.next = task.next;
        } else {
            self.head = task.next;
        }
        if task.next.is_some() {
            let next = task.next.as_mut().unwrap();
            next.prev = task.prev;
        } else {
            self.tail = task.prev;
        }
    }

    fn get_by_priority(&self, priority: u8) -> Vec<usize> {
        let mut result = Vec::new();
        let mut current = self.head.as_mut().unwrap();
        while current.is_some() {
            if current.as_ref().unwrap().priority == priority {
                result.push(current.as_ref().unwrap().id);
            }
            current = current.as_ref().unwrap().next.as_mut().unwrap();
        }
        result
    }

    fn get_all(&self) -> Vec<(&String, u8)> {
        let mut result = Vec::new();
        let mut current = self.head.as_mut().unwrap();
        while current.is_some() {
            result.push((current.as_ref().unwrap().content.clone(), current.as_ref().unwrap().priority));
            current = current.as_ref().unwrap().next.as_mut().unwrap();
        }
        result
    }
}

fn main() {
    let task_list = TaskList::new();
    let task_list_clone = task_list;

    let mut threads = vec![];

    // Create 5 threads to simulate concurrent task management
    for _ in 0..5 {
        let task_list = task_list_clone;
        let thread = thread::spawn(move || {
            // Simulate inserting tasks
            for i in 1..10 {
                let task = Task {
                    id: i,
                    priority: 5 - (i % 2),
                    content: format!("Task {}", i),
                    next: None,
                    prev: None,
                };
                task_list.insert(task);
                thread.sleep(Duration::from_millis(100));
            }
        });
        threads.push(thread);
    }

    // Wait for all threads to finish
    for thread in threads {
        thread.join().unwrap();
    }
}
