        cout << "Enter performance score (0-100): ";
        if (cin >> score && score >= 0 && score <= 100) {
            break;
        }
        cin.clear();
        cin.ignore(numeric_limits<streamsize>::max(), '\n');
        cout << "Invalid input. Please enter a score between 0 and 100." << endl;
    }
}

void insertSort(vector<Employee>& employees) {
    for (int i = 1; i < employees.size(); ++i) {
        Employee key = employees[i];
        int j = i - 1;
        while (j >= 0 && employees[j].performanceScore > key.performanceScore) {
            employees[j + 1] = employees[j];
            --j;
        }
        employees[j + 1] = key;
    }
}

void displayEmployees(const vector<Employee>& employees) {
    for (const auto& emp : employees) {
        cout << "ID: " << emp.id << ", Name: " << emp.name << ", Performance Score: " << emp.performanceScore << endl;
    }
}

