class DynamicLeaderboard {
private:
    std::vector<int> scores;
    std::vector<std::string> playerIds;
    std::vector<std::pair<int, std::string>> leaderboard;
    std::mutex mtx;
    std::thread updateThread;
    bool running;

public:
    DynamicLeaderboard() : running(false) {
        // Initialize with some dummy data
        scores = {100, 90, 80, 70, 60};
        playerIds = {"P1", "P2", "P3", "P4", "P5"};
        leaderboard = std::vector<std::pair<int, std::string>>();
        for (size_t i = 0; i < scores.size(); ++i) {
            leaderboard.push_back({scores[i], playerIds[i]});
        }
        running = true;
    }

    ~DynamicLeaderboard() {
        running = false;
        updateThread.join();
    }

    void updateScore(int playerId, int newScore) {
        std::lock_guard<std::mutex> lock(mtx);
        auto it = std::find_if(leaderboard.begin(), leaderboard.end(),
                               [playerId](const auto& pair) {
                                   return pair.second == playerId;
                               });
        if (it != leaderboard.end()) {
            int oldScore = it->first;
            it->first = newScore;
            std::sort(leaderboard.begin(), leaderboard.end(),
                      [](const auto& a, const auto& b) {
                          return a.first > b.first;
                      });
        }
    }

    void startUpdating() {
        updateThread = std::thread([this]() {
            while (running) {
                // Simulate real-time score updates
                std::this_thread::sleep_for(std::chrono::milliseconds(100));
                int newScore = rand() % 100 + 1;
                updateScore(playerIds[0], newScore);
            }
        });
    }

    void stopUpdating() {
        running = false;
        updateThread.join();
    }

    void printLeaderboard() {
        std::sort(leaderboard.begin(), leaderboard.end(),
                  [](const auto& a, const auto& b) {
                      return a.first > b.first;
                  });
        for (const auto& entry : leaderboard) {
            std::cout << entry.second << " - " << entry.first << std::endl;
        }
    }
};

int main() {
    DynamicLeaderboard leaderboard;
    leaderboard.startUpdating();
    leaderboard.printLeaderboard();
    return 0;
}

