// Function to find the longest common subsequence (LCS) between two strings
int lcs(int len1, char* str1, int len2, char* str2) {
    int dp[len2 + 1][len1 + 1];
    for (int i = 0; i <= len2; i++) {
        for (int j = 0; j <= len1; j++) {
            if (i == 0 || j == 0) {
                dp[i][j] = 0;
            } else if (str1[j-1] == str2[i-1]) {
                dp[i][j] = dp[i-1][j-1] + 1;
            } else {
                dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
            }
        }
    }
    return dp[len2][len1];
}

// Function to read documents and find the LCS
void findLCS(char** documents, int numDocs) {
    int maxLen = 0;
    char* lcs = NULL;

    // Find LCS of all documents
    for (int i = 0; i < numDocs; i++) {
        for (int j = 0; j < numDocs; j++) {
            if (i == j) {
                // LCS of document i with itself is the document itself
                int currentLen = strlen(documents[i]);
                if (currentLen > maxLen) {
                    maxLen = currentLen;
                    lcs = strdup(documents[i]);
                }
            } else {
                // Compute LCS of documents[i] and documents[j]
                int len = lcs(documents[i], documents[j], strlen(documents[i]), strlen(documents[j]));
                if (len > maxLen) {
                    maxLen = len;
                    lcs = strdup(documents[i]);
                }
            }
        }
    }

    // Output the result
    printf("Largest Common Subsequence: %s\n", lcs);
    free(lcs);
}

