// Define packet structure
typedef struct packet {
    int priority;
    char data[1024];
    struct packet* next;
} Packet;

// Priority queue (using a heap)
typedef struct {
    Packet* elements;
    int size;
    int capacity;
} PriorityQueue;

// Function to create a new packet
Packet* create_packet(int priority, const char* data) {
    Packet* packet = (Packet*)malloc(sizeof(Packet));
    if (!packet) return NULL;
    packet->priority = priority;
    strncpy(packet->data, data, sizeof(packet->data) - 1);
    packet->next = NULL;
    return packet;
}

// Function to push a packet into the priority queue
void push_priority_queue(PriorityQueue* pq, Packet* packet) {
    if (!pq || !packet) return;
    packet->next = NULL;
    if (pq->size == pq->capacity) {
        // Resize the queue if needed
        Packet* temp = (Packet*)malloc(pq->capacity * sizeof(Packet));
        if (temp) {
            memcpy(temp, pq->elements, pq->capacity * sizeof(Packet));
            free(pq->elements);
            pq->elements = temp;
            pq->capacity *= 2;
        }
    }
    memcpy(pq->elements + pq->size, packet, sizeof(Packet));
    pq->size++;
    pq->elements[pq->size - 1].next = NULL;
    // Heapify after insertion
    heapify(pq);
}

// Function to pop a packet from the priority queue
Packet* pop_priority_queue(PriorityQueue* pq) {
    if (!pq || pq->size == 0) return NULL;
    Packet* packet = pq->elements[0];
    // Remove the root
    memcpy(pq->elements, pq->elements + 1, (pq->size - 1) * sizeof(Packet));
    pq->size--;
    // Rebuild heap
    heapify(pq);
    return packet;
}

// Function to heapify the priority queue
void heapify(PriorityQueue* pq) {
    int i, j;
    Packet* temp;
    for (i = 0; i < pq->size; i++) {
        temp = pq->elements[i];
        j = i;
        while (j > 0) {
            int parent = (j - 1) / 2;
            if (pq->elements[parent]->priority < temp->priority) {
                // Swap
                Packet* swap = temp;
                temp = pq->elements[parent];
                pq->elements[parent] = swap;
                j = parent;
            } else {
                break;
            }
        }
    }
}

// Function to print the priority queue
void print_queue(PriorityQueue* pq) {
    if (!pq || pq->size == 0) return;
    for (int i = 0; i < pq->size; i++) {
        printf("Priority: %d, Data: %s\n", pq->elements[i]->priority, pq->elements[i]->data);
    }
}

// Function to validate packet data
int validate_packet(const char* data) {
    if (!data || strlen(data) > 1024) return 0;
    return 1;
}

// Function to log a message
void log_message(const char* message) {
    printf("Log: %s\n", message);
}

// Main function
int main() {
    // Initialize priority queue
    PriorityQueue pq = {NULL, 0, 0};
    int capacity = 4;
    pq.capacity = capacity;
    pq.elements = (Packet*)malloc(capacity * sizeof(Packet));

    // Example packet creation
    Packet* packet1 = create_packet(1, "Packet 1");
    Packet* packet2 = create_packet(2, "Packet 2");
    Packet* packet3 = create_packet(3, "Packet 3");

    // Push packets into the queue
    push_priority_queue(&pq, packet1);
    push_priority_queue(&pq, packet2);
    push_priority_queue(&pq, packet3);

    // Process packets
    while (pq.size > 0) {
        Packet* processed = pop_priority_queue(&pq);
        log_message("Processed packet: priority = %d, data = %s", processed->priority, processed->data);
        free(processed);
    }

    // Free allocated memory
    free(pq.elements);
    return 0;
}

