fn is_safe(board: &Vec<Vec<u8>>, row: usize, col: usize, n: usize) -> bool {
    for i in 0..row {
        if board[i][col] == 1 || board[i][col] == 2 {
            return false;
        }
        if board[row][col] == 1 {
            return false;
        }
        if board[row][col] == 2 {
            return false;
        }
        if board[i][col] == 1 {
            return false;
        }
        if board[row][col] == 1 {
            return false;
        }
        if board[row][col] == 2 {
            return false;
        }
        if board[i][col] == 1 {
            return false;
        }
        if board[row][col] == 1 {
            return false;
        }
        if board[row][col] == 2 {
            return false;
        }
    }
    true
}

fn solve_n_queens(n: usize) -> Vec<Vec<Vec<u8>>> {
    let mut result = Vec::new();
    let mut board = vec![vec![0; n]; n];
    let mut visited = vec![false; n];
    let mut queen_positions = Vec::new();

    fn backtrack(row: usize, board: &mut Vec<Vec<u8>>, visited: &mut Vec<bool>, queen_positions: &mut Vec<(usize, usize)>) -> bool {
        if row == n {
            result.push(board.clone());
            return true;
        }
        for col in 0..n {
            if visited[col] {
                continue;
            }
            if is_safe(board, row, col, n) {
                visited[col] = true;
                board[row][col] = 1;
                queen_positions.push((row, col));
                if backtrack(row + 1, board, visited, queen_positions) {
                    return true;
                }
                visited[col] = false;
                board[row][col] = 0;
                queen_positions.pop();
            }
        }
        false
    }

    backtrack(0, &mut board, &mut visited, &mut queen_positions);
    result
}

fn visualize_board(board: &Vec<Vec<u8>>, n: usize) {
    for row in 0..n {
        for col in 0..n {
            if board[row][col] == 1 {
                print("Q ");
            } else if board[row][col] == 2 {
                print("R ");
            } else {
                print(". ");
            }
        }
        println!();
    }
}

fn main() {
    let n = 8;
    let solutions = solve_n_queens(n);
    println!("Number of solutions: {}", solutions.len());
    for solution in solutions {
        visualize_board(&solution, n);
    }
}
