function shortestPath(graph, start, end) {
    if (!graph || !graph.nodes || !graph.edges || !graph.nodes[start] || !graph.nodes[end]) {
        throw new Error("Invalid input: start or end not found in the graph.");
    }

    const dist = {};
    const prev = {};
    const visited = new Set();
    const priorityQueue = [[0, start]];

    while (priorityQueue.length > 0) {
        const [currentDist, current] = priorityQueue.shift();
        if (current === end) {
            break;
        }
        if (visited.has(current)) {
            continue;
        }
        visited.add(current);
        dist[current] = currentDist;

        for (const [neighbor, weight] of graph.edges[current]) {
            const newDist = currentDist + weight;
            if (!dist[neighbor] || newDist < dist[neighbor]) {
                dist[neighbor] = newDist;
                prev[neighbor] = current;
                priorityQueue.push([newDist, neighbor]);
            }
        }
    }

    if (!dist[end]) {
        throw new Error("No path found between the specified intersections.");
    }

    const path = [];
    let current = end;
    while (current !== start) {
        path.push(current);
        current = prev[current];
    }
    path.push(start);
    path.reverse();

    return path;
}
