import java.util.*;

public class ConfigManager {
    private final Map<String, String> configMap = new HashMap<>();
    private final String propertiesFilePath;

    public ConfigManager(String propertiesFilePath) {
        this.propertiesFilePath = propertiesFilePath;
        loadProperties();
    }

    private void loadProperties() {
        try (FileInputStream fis = new FileInputStream(propertiesFilePath);
             Properties prop = new Properties()) {
            prop.load(fis);
            configMap.putAll(prop);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public String get(String key) {
        return configMap.getOrDefault(key, null);
    }

    public void set(String key, String value) {
        configMap.put(key, value);
    }

    public void reloadProperties() {
        configMap.clear();
        loadProperties();
    }

    public void validateKeyFormat(String key) {
        if (key == null || key.isEmpty()) {
            throw new IllegalArgumentException("Key cannot be null or empty");
        }
        if (key.contains(",")) {
            throw new IllegalArgumentException("Key cannot contain commas");
        }
    }

    public void validateValueFormat(String value) {
        if (value == null || value.isEmpty()) {
            throw new IllegalArgumentException("Value cannot be null or empty");
        }
        if (value.contains(",")) {
            throw new IllegalArgumentException("Value cannot contain commas");
        }
    }

    public void resolveDuplicateKeys(String key) {
        if (configMap.containsKey(key)) {
            throw new IllegalArgumentException("Duplicate key: " + key);
        }
