using namespace std;

const int BOARD_SIZE = 8;

vector<vector<int>> board;

void loadBoard(const string& filename) {
    ifstream file(filename);
    if (!file.is_open()) {
        throw runtime_error("Cannot open file");
    }
    string line;
    while (getline(file, line)) {
        istringstream iss(line);
        int pos;
        vector<int> row;
        while (iss >> pos) {
            row.push_back(pos);
        }
        board.push_back(row);
    }
}

bool isValid(int row, int col) {
    for (int i = 0; i < row; i++) {
        if (board[i][col] == 1 || board[row][i] == 1) {
            return false;
        }
    }
    return true;
}

void printBoard() {
    for (int i = 0; i < BOARD_SIZE; i++) {
        for (int j = 0; j < BOARD_SIZE; j++) {
            cout << (board[i][j] ? 'Q' : '.');
        }
        cout << endl;
    }
}

bool backtrack(int row) {
    if (row == BOARD_SIZE) {
        printBoard();
        return true;
    }
    for (int col = 0; col < BOARD_SIZE; col++) {
        if (isValid(row, col)) {
            board[row][col] = 1;
            if (backtrack(row + 1)) {
                return true;
            }
            board[row][col] = 0;
        }
    }
    return false;
}

int main() {
    try {
        string filename;
        cout << "Enter filename: ";
        cin >> filename;
        loadBoard(filename);
        backtrack(0);
    } catch (const exception& e) {
        cout << "Error: " << e.what() << endl;
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <stdexcept>

class PriorityQueue {
private:
    std::vector<int> heap;
    size_t size;

public:
    PriorityQueue() : size(0) {}

    // Insert element into the priority queue
    void insert(int value) {
        heap.push_back(value);
        size++;
        siftUp(size - 1);
    }

    // Remove the minimum element
    int removeMin() {
        if (size == 0) {
            throw std::out_of_range("Priority queue is empty");
        }
        int minVal = heap[0];
        heap[0] = heap[size - 1];
        heap.pop_back();
        size--;
        siftDown(0);
        return minVal;
    }

    // Retrieve the minimum element
    int getMin() {
        if (size == 0) {
            throw std::out_of_range("Priority queue is empty");
        }
        return heap[0];
    }

    // Sift up the element at index
    void siftUp(size_t index) {
        while (index > 0) {
            size_t parent = (index - 1) / 2;
            if (heap[index] <= heap[parent]) {
                break;
            }
            std::swap(heap[index], heap[parent]);
            index = parent;
        }
    }

    // Sift down the element at index
    void siftDown(size_t index) {
        while (index < size) {
            size_t left = 2 * index + 1;
            size_t right = 2 * index + 2;
            size_t smallest = index;

            if (left < size && heap[left] < heap[smallest]) {
                smallest = left;
            }

            if (right < size && heap[right] < heap[smallest]) {
                smallest = right;
            }

            if (smallest != index) {
                std::swap(heap[index], heap[smallest]);
                index = smallest;
            } else {
                break;
            }
        }
    }

    // Get the size of the priority queue
    size_t getSize() {
        return size;
    }
};

int main() {
    PriorityQueue pq;
    pq.insert(10);
    pq.insert(20);
    pq.insert(5);
    pq.insert(15);

    std::cout << "Minimum element: " << pq.getMin() << std::endl;
    std::cout << "Size: " << pq.getSize() << std::endl;

    try {
        std::cout << "Removing minimum: " << pq.removeMin() << std::endl;
        std::cout << "Size: " << pq.getSize() << std::endl;
    } catch (const std::out_of_range& e) {
        std::cout << "Error: " << e.what() << std::endl;
    }

    return 0;
}

