struct Location {
    double x;
    double y;
};

double distance(const Location& loc1, const Location& loc2) {
    return std::sqrt(std::pow(loc1.x - loc2.x, 2) + std::pow(loc1.y - loc2.y, 2));
}

double closestDistance(const std::vector<Location>& locations, const Location& userLoc) {
    double minDistance = std::numeric_limits<double>::infinity();
    Location closestShop;

    for (const auto& loc : locations) {
        double dist = distance(loc, userLoc);
        if (dist < minDistance) {
            minDistance = dist;
            closestShop = loc;
        }
    }

    return minDistance;
}

int main() {
    std::vector<Location> locations = {
        {10.5, 20.3},
        {15.2, 18.7},
        {22.1, 25.4},
        {30.8, 22.9},
        {27.6, 28.1}
    };

    Location userLoc = {15.0, 22.0};

    double minDistance = closestDistance(locations, userLoc);
    std::cout << "Closest coffee shop is at (" << closestShop.x << ", " << closestShop.y << ") with distance: " << minDistance << std::endl;

    return 0;
}

public class SubarraySum {
    public static int maxSubarraySum(int[] arr) {
        int maxCurrent = arr[0];
        int maxGlobal = arr[0];

        for (int i = 1; i < arr.length; i++) {
            maxCurrent = Math.max(arr[i], maxCurrent + arr[i]);
            maxGlobal = Math.max(maxGlobal, maxCurrent);
        }

        return maxGlobal;
    }
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int main() {
    // Example cities and distances
    vector<pair<string, int>> cities = {
        {"New York", 100},
        {"Los Angeles", 150},
        {"Chicago", 200},
        {"Philadelphia", 250}
    };

    // Number of cities
    int n = cities.size();

    // Initialize distance matrix
    vector<vector<int>> dist(n, vector<int>(n, 0));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j)
                dist[i][j] = 0;
            else
                dist[i][j] = cities[i].second;
        }
    }

    // Solve TSP
    vector<int> path;
    vector<bool> visited(n, false);
    path.push_back(0);
    visited[0] = true;

    for (int i = 0; i < n - 1; i++) {
        int min_dist = INT_MAX;
        int next_city = -1;

        for (int j = 0; j < n; j++) {
            if (!visited[j] && dist[path[i]][j] < min_dist) {
                min_dist = dist[path[i]][j];
                next_city = j;
            }
        }

        path.push_back(next_city);
        visited[next_city] = true;
    }

    // Return to origin
    path.push_back(0);
    visited[0] = true;

    // Output the path
    cout << "Optimal path: ";
    for (int i = 0; i < n; i++) {
        cout << cities[path[i]].first << " ";
    }
    cout << endl;

    return 0;
}
